## Frontend Patterns Report: Nam Phương ERP Accounting Pages

Based on my exploration of the ERP project, here are the **exact code patterns** for adding new accounting pages:

---

### 1. **BankReconciliationPage.tsx** (Current Stub)
**Location:** `/frontend/src/pages/accounting/BankReconciliationPage.tsx`

Currently minimal:
```tsx
export default function BankReconciliationPage() {
  return (
    <div style={{ padding: 24 }}>
      <h2>Đối soát ngân hàng</h2>
      <p>Tính năng đang phát triển.</p>
    </div>
  )
}
```

This is the template to replace.

---

### 2. **Route Registration Pattern**
**Location:** `/frontend/src/App.tsx`

**Pattern for accounting routes (lines 421-450):**

```tsx
// Lazy load
const BankReconciliationPage = lazy(() => import('./pages/accounting/BankReconciliationPage'))

// Inside <Routes>
<Route path="accounting/receipts" element={<CashReceiptListPage />} />
<Route path="accounting/receipts/new" element={<CashReceiptForm />} />
<Route path="accounting/receipts/:id" element={<CashReceiptDetailPage />} />
<Route path="accounting/payments" element={<CashPaymentListPage />} />
<Route path="accounting/payments/new" element={<CashPaymentForm />} />
<Route path="accounting/payments/:id" element={<CashPaymentDetailPage />} />
<Route path="accounting/bank-reconciliation" element={<BankReconciliationPage />} />
```

**For new pages:**
- Add lazy import at top
- Add `<Route path="accounting/[new-slug]" element={<ErrorBoundary><YourPage /></ErrorBoundary>} />`
- Wrap with `<ErrorBoundary>` for error handling

---

### 3. **Menu Navigation Pattern**
**Location:** `/frontend/src/pages/accounting/AccountingHubPage.tsx`

Structure for adding menu items:

```tsx
const GROUPS: HubGroup[] = [
  {
    title: 'Quỹ & Ngân hàng',
    items: [
      { icon: '💵', label: 'Phiếu thu', to: '/accounting/receipts' },
      { icon: '💸', label: 'Phiếu chi', to: '/accounting/payments' },
      { icon: '📒', label: 'Sổ quỹ tiền mặt', to: '/accounting/cash-book' },
      { icon: '🏦', label: 'Sổ tiền gửi NH', to: '/accounting/bank-ledger' },
      { icon: '🔄', label: 'Đối soát ngân hàng', to: '/accounting/bank-reconciliation' },
    ],
  },
  // ... more groups
]
```

**Add new pages to relevant group with:**
- `icon`: emoji (single character)
- `label`: Vietnamese display name
- `to`: route path
- `permissions?`: optional array of required permissions

---

### 4. **API Layer Pattern**
**Location:** `/frontend/src/api/accounting.ts`

**For list/CRUD operations:**

```tsx
// Define interfaces
export interface YourEntity {
  id: number
  so_phieu: string  // document number
  ngay: string      // date (YYYY-MM-DD)
  trang_thai: string // status
  // ... other fields
}

export interface YourEntityCreate {
  // Required and optional create fields
}

// Define status constants
export const TRANG_THAI_YOUR_ENTITY: Record<string, { label: string; color: string }> = {
  nhap: { label: 'Nháp', color: 'default' },
  da_duyet: { label: 'Đã duyệt', color: 'green' },
  huy: { label: 'Đã hủy', color: 'default' },
}

// API endpoints
export const yourEntityApi = {
  list: (params?: Record<string, unknown>) =>
    client.get('/accounting/your-entity', { params }).then(r => r.data),

  get: (id: number): Promise<YourEntity> =>
    client.get(`/accounting/your-entity/${id}`).then(r => r.data),

  create: (data: YourEntityCreate): Promise<YourEntity> =>
    client.post('/accounting/your-entity', data).then(r => r.data),

  approve: (id: number): Promise<YourEntity> =>
    client.patch(`/accounting/your-entity/${id}/approve`).then(r => r.data),

  cancel: (id: number): Promise<YourEntity> =>
    client.patch(`/accounting/your-entity/${id}/cancel`).then(r => r.data),
}
```

**Key pattern:** `client.get/post/patch(...).then(r => r.data)` strips response wrapper.

---

### 5. **List Page Pattern (Complete Example)**
**Location:** `/frontend/src/pages/accounting/CashReceiptListPage.tsx` and `/frontend/src/pages/accounting/CashPaymentListPage.tsx`

**Exact structure to follow:**

```tsx
import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useHotkey } from '../../hooks/useHotkey'
import { useQuery } from '@tanstack/react-query'
import {
  Button, Card, Col, DatePicker, Row, Select, Space, Table, Tag, Typography,
} from 'antd'
import { PlusOutlined, FileExcelOutlined } from '@ant-design/icons'
import type { ColumnsType } from 'antd/es/table'
import dayjs from 'dayjs'
import { exportToExcel, fmtVND } from '../../utils/exportUtils'
import { yourEntityApi, YourEntity, TRANG_THAI_ENTITY } from '../../api/accounting'
import { usePhapNhan } from '../../hooks/useMasterData'
import EmptyState from "../../components/EmptyState"
import PageLayout from '../../components/PageLayout'

const { Text } = Typography
const { RangePicker } = DatePicker

export default function YourEntityListPage() {
  const navigate = useNavigate()
  const { phapNhanList } = usePhapNhan()
  const [tuNgay, setTuNgay] = useState<string | undefined>()
  const [denNgay, setDenNgay] = useState<string | undefined>()
  const [filterTrangThai, setFilterTrangThai] = useState<string | undefined>()
  const [filterPhapNhan, setFilterPhapNhan] = useState<number | undefined>()
  const [page, setPage] = useState(1)

  // React Query pattern
  const { data, isLoading } = useQuery({
    queryKey: ['your-entity', tuNgay, denNgay, filterTrangThai, filterPhapNhan, page],
    queryFn: () =>
      yourEntityApi.list({
        tu_ngay: tuNgay,
        den_ngay: denNgay,
        trang_thai: filterTrangThai,
        phap_nhan_id: filterPhapNhan,
        page,
        page_size: 20,
      }),
  })

  // Data extraction pattern
  const items: YourEntity[] = data?.items ?? data ?? []
  const total: number = data?.total ?? items.length
  const tongSoTien = items.reduce((s: number, r: YourEntity) => s + (r.so_tien ?? 0), 0)

  // Excel export
  const handleExcel = () => {
    const rows = items.map((r: YourEntity) => ({
      'Số phiếu': r.so_phieu,
      'Ngày': r.ngay,
      // ... other columns
    }))
    exportToExcel(`your-entity-${dayjs().format('YYYYMMDD')}`, [{
      name: 'SheetName',
      headers: Object.keys(rows[0] ?? {}),
      rows: rows.map((r: Record<string, string | number>) => Object.values(r)),
    }])
  }

  // Hotkey for quick create
  useHotkey('ctrl+n', () => navigate('/accounting/your-entity/new'), 'Tạo mới')

  // Table columns definition
  const columns: ColumnsType<YourEntity> = [
    {
      title: 'Số phiếu',
      dataIndex: 'so_phieu',
      width: 160,
      render: (v, r) => <a onClick={() => navigate(`/accounting/your-entity/${r.id}`)}>{v}</a>,
    },
    {
      title: 'Ngày',
      dataIndex: 'ngay',
      width: 110,
      render: v => dayjs(v).format('DD/MM/YYYY'),
    },
    {
      title: 'Trạng thái',
      dataIndex: 'trang_thai',
      width: 120,
      render: v => {
        const s = TRANG_THAI_ENTITY[v]
        return <Tag color={s?.color}>{s?.label ?? v}</Tag>
      },
    },
    // ... more columns
  ]

  return (
    <PageLayout
      title="Your Entity Title"
      actions={
        <Space>
          <Button icon={<FileExcelOutlined />} onClick={handleExcel}>Excel</Button>
          <Button type="primary" icon={<PlusOutlined />} onClick={() => navigate('/accounting/your-entity/new')}>
            Tạo mới
          </Button>
        </Space>
      }
    >
      {/* Filters Card */}
      <Card size="small" style={{ marginBottom: 12 }}>
        <Row gutter={[12, 8]} align="middle">
          <Col>
            <RangePicker
              format="DD/MM/YYYY"
              placeholder={['Từ ngày', 'Đến ngày']}
              onChange={v => {
                setTuNgay(v?.[0]?.format('YYYY-MM-DD'))
                setDenNgay(v?.[1]?.format('YYYY-MM-DD'))
                setPage(1)
              }}
            />
          </Col>
          <Col>
            <Select
              style={{ width: 160 }} allowClear placeholder="Trạng thái"
              onChange={v => { setFilterTrangThai(v); setPage(1) }}
              options={Object.entries(TRANG_THAI_ENTITY).map(([k, v]) => ({ value: k, label: v.label }))}
            />
          </Col>
          <Col>
            <Select
              style={{ width: 180 }} allowClear placeholder="Pháp nhân"
              onChange={v => { setFilterPhapNhan(v); setPage(1) }}
              options={phapNhanList.map(p => ({ value: p.id, label: p.ten_phap_nhan }))}
            />
          </Col>
        </Row>
      </Card>

      {/* Table */}
      <Card size="small" loading={isLoading}>
        <Table<YourEntity>
          columns={columns}
          dataSource={items}
          pagination={{ current: page, pageSize: 20, total, onChange: setPage }}
          locale={{ emptyText: <EmptyState /> }}
          size="small"
          rowKey="id"
        />
      </Card>
    </PageLayout>
  )
}
```

